from pypdf import PdfReader, PdfWriter
import io
import base64

def main(input):

    """
    Split PDF into single-page PDFs for Workato IDP processing
    """

    if not input:
        return {
            "status": "INVALID_INPUT",
            "message": "Input is empty",
            "pages": []
        }

    filecontents = input.get("filecontents") or input.get("filecontent")
    original_file_name = input.get("file_name", "source.pdf")

    # Handle Workato array
    if isinstance(filecontents, list) and filecontents:
        filecontents = filecontents[0]

    # Extract raw content
    if isinstance(filecontents, dict):
        raw = filecontents.get("content")
    else:
        raw = filecontents

    if not raw:
        return {
            "status": "EMPTY_FILE",
            "message": "No file content provided",
            "pages": []
        }

    # Convert to bytes
    pdf_bytes = None

    if isinstance(raw, bytes):
        pdf_bytes = raw

    elif isinstance(raw, str):

        try:
            pdf_bytes = base64.b64decode(raw, validate=True)

        except Exception:

            try:
                pdf_bytes = raw.encode("latin1")

            except Exception:
                return {
                    "status": "INVALID_FORMAT",
                    "message": "Unable to decode file content",
                    "pages": []
                }

    else:
        return {
            "status": "INVALID_FORMAT",
            "message": "Unsupported file format",
            "pages": []
        }

    # Validate PDF
    if not pdf_bytes.startswith(b"%PDF"):
        return {
            "status": "INVALID_PDF",
            "message": "Missing PDF header",
            "pages": []
        }

    # Read PDF
    try:
        reader = PdfReader(io.BytesIO(pdf_bytes))

    except Exception as e:
        return {
            "status": "INVALID_PDF",
            "message": str(e),
            "pages": []
        }

    # Split Pages
    output_pages = []

    for idx, page in enumerate(reader.pages):

        writer = PdfWriter()
        writer.add_page(page)

        buffer = io.BytesIO()
        writer.write(buffer)

        split_pdf_bytes = buffer.getvalue()

        encoded = base64.b64encode(split_pdf_bytes).decode("utf-8")

        output_pages.append({
            "page_number": idx + 1,
            "file_name": f"page_{idx+1}.pdf",
            "original_file_name": original_file_name,
            "content": encoded
        })

    return {
        "status": "SUCCESS",
        "total_pages": len(output_pages),
        "pages": output_pages
    }

def main(input):
    """
    Identify low-confidence fields and mark overall status
    as FAILED if any confidence score is < 0.95
    """

    # ✅ 1. Guard against empty input
    input = input or {}

    # ✅ 2. Get extracted data safely
    data = input.get("extracted_data") or {}

    # ✅ 3. Fixed threshold = 0.95
    threshold = 0.95

    cleaned_data = {}
    low_confidence_fields = []

    def process_field(key, value):

        # Case 1: Field contains value + confidence
        if isinstance(value, dict) and "value" in value:

            field_value = value.get("value")
            confidence = float(value.get("confidence", 1))

            cleaned_data[key] = field_value

            # 🔥 Mark as failed if confidence < 0.95
            if confidence < threshold:
                low_confidence_fields.append({
                    "field_name": key,
                    "value": field_value,
                    "confidence": confidence
                })

        # Case 2: Nested list (line items)
        elif isinstance(value, list):

            cleaned_data[key] = []

            for idx, item in enumerate(value):

                # Handle non-dict items safely
                if not isinstance(item, dict):
                    cleaned_data[key].append(item)
                    continue

                item_clean = {}

                for sub_key, sub_val in item.items():

                    if isinstance(sub_val, dict) and "value" in sub_val:

                        field_value = sub_val.get("value")
                        confidence = float(sub_val.get("confidence", 1))

                        item_clean[sub_key] = field_value

                        # 🔥 Mark as failed if confidence < 0.95
                        if confidence < threshold:
                            low_confidence_fields.append({
                                "field_name": f"{key}[{idx}].{sub_key}",
                                "value": field_value,
                                "confidence": confidence
                            })

                    else:
                        item_clean[sub_key] = sub_val

                cleaned_data[key].append(item_clean)

        # Case 3: Plain value
        else:
            cleaned_data[key] = value

    # ✅ Process all fields safely
    if isinstance(data, dict):
        for k, v in data.items():
            process_field(k, v)

    # 🔥 Final Decision
    if len(low_confidence_fields) > 0:

        status = "FAILED"
        needs_review = "True"
        message = "Invoice failed due to confidence score below 0.95"

    else:

        status = "SUCCESS"
        needs_review = "False"
        message = "All confidence scores are above 0.95"

    return {
        "status": status,
        "cleaned_data": cleaned_data,
        "low_confidence_fields": low_confidence_fields,
        "needs_review": needs_review,
        "message": message
    }
